	output logic rst_1;
	output logic rst_2;
	output logic rst_3;
	output logic rst_4;
	output logic rst_5;
	output logic rst_6;
	output logic rst_7;
	output logic rst_8;
	output logic rst_9;
	output logic rst_10;
	output logic rst_11;
	output logic rst_13;

	logic rst_12;

	// internal signals
	logic start;

	logic [4:0]  rst_id;
	logic [13:0] rst_mem;

	// reset logic: if start is high, set to rst memory, otherwise keep at default
	assign rst_1 = rst_mem[1]; // AES0
	assign rst_2 = rst_mem[2]; // AES1
	assign rst_3 = rst_mem[3]; // SHA256
	assign rst_4 = rst_mem[4]; // HMAC
	assign rst_5 = rst_mem[5]; // PKT
	assign rst_6 = rst_mem[6]; // ACCT
	assign rst_7 = rst_mem[7]; // UART
	assign rst_8 = rst_mem[8]; // DMA
	assign rst_9 = rst_mem[9]; // REGLK
	assign rst_10 = rst_mem[10]; // RNG
	assign rst_11 = rst_mem[11]; // AES2
	assign rst_12 = rst_mem[12]; // RST_CTRL
	assign rst_13 = rst_mem[13]; // RSA

// rst vector logic
always @(posedge clk_i) begin
	if (~rst_ni || rst_12) begin
			rst_mem <= 0;
	end else if (start) begin
		case (rst_id)
			0: // ROM
				rst_mem[0] <= 1;
			1: // AES0
				rst_mem[1] <= 1;
			2: // AES1
				rst_mem[2] <= 1;
			3: // SHA256
				rst_mem[3] <= 1;
			4: // HMAC
				rst_mem[4] <= 1;
			5: // PKT
				rst_mem[5] <= 1;
			6: // ACCT
				rst_mem[6] <= 1;
			7: // UART	
				rst_mem[7] <= 1;
			8: // DMA
				rst_mem[8] <= 1;
			9: // REGLK
				rst_mem[9] <= 1;
			10: // RNG
				rst_mem[10] <= 1;
			11: // AES2
				rst_mem[11] <= 1;
			12: // RST_CTRL - the peripheral itself
				rst_mem[12] <= 1;
			13: // RSA
				rst_mem[13] <= 1;
		endcase
	end else begin
		rst_mem <= 0;
	end
end


